sp_widget.client_script:
api.controller=function($scope, $location, $rootScope, spModal, $uibModal, spUtil, amb, $timeout, $log, $window) {
  /* widget controller */
  var c = this;
	// used in _switchTaskFormView to switch form 
	var newObjSelected = {};
	main();
	function main(){
		c.data.submitting = false;
		c.data.promptChangesStarted = false;
		c.data.redirectToNew = false;
		// currently no code in main
	}

	// ServiceNow dirty flag still popping up, need to figure out how to block it
	$scope.$on('$locationChangeStart', function (event, next, current) {
		var loc = $location.search();
		// url change is actually saving data, skip function in this call
		// this method was added to prompt for save on attempting to leave page
		if(loc.id=="discovertasker_newtask"){
			return undefined;
		}
		if(!c.data.submitting && 
			 !c.data.promptChangesStarted && 
			 !c.data.redirectToNew &&
			 next && current && next != current){
			var isDataDirty = c.data.new_task_widget_forms[0].widget.checkChanges();
			var nextURL = $location.path();
			if(isDataDirty ){
				_promptDiscardChanges(false, nextURL);
			} else {
				$location.url(nextURL);
				return undefined;

			}
			return undefined;
		}
	});	

	$scope.selectType= function(objSelected){
		// used in _switchTaskFormView to switch form 
		newObjSelected = undefined; // clear selected object
		newObjSelected = objSelected;
		var isDataDirty = c.data.new_task_widget_forms[0].widget.checkChanges();
		// if dirty, or, this is a saved task and changing the view
		// prompt user
		if(isDataDirty || 
			 (c.data.sys_id && c.data.sys_id != -1 && 
			 c.data.view != newObjSelected.sn_view)){
			_promptDiscardChanges(true);
		} else {
			_switchTaskFormView(true);
		}
	}

	function _promptDiscardChanges(switchTaskFormView, newURL){
		var title = "";
		if(!c.data.sys_id || c.data.sys_id == -1){
			title = c.data.messages["Tasker - Delete Form Data"];
		} else {
			title = c.data.messages["Tasker - Update Form View"];
		}
		var modalSelection = {};
		spModal.open({
			title: title,
			widgetInput: {
				sys_id: c.data.sys_id
			},
			backdrop: 'static',
			widget: 'tasker_modal_save_draft_prompt',
			size: 'md',
			shared: modalSelection,
			buttons: [],
			footerStyle: {
				'display': 'none'
			}
		}).then(function(response) {
			// here when a primary button (Save as Draft OR Discard Changes)
			if(modalSelection.saveDraft){
				c.data.newRec = {};

				// if no sys_id, the post back is called below once the sys_id is returned
				// call here if sys_id exists, no need to wait for save to complete
				if(!c.data.sys_id || c.data.sys_id == -1){
					c.data.promptChangesStarted = true;
					c.data.new_task_widget_forms[0].widget.saveAsDraft(newObjSelected);	
				} else {
					if(switchTaskFormView){
						_switchTaskFormView(true);
					} 
					// if not switching forms, no need to redirect to new url on save
					// so no need to do anything if save selected when form closed
				}
			}else if(modalSelection.discardChanges){
				// discard changes selected, change the view, but don't save the form changes
				if(switchTaskFormView){
					_switchTaskFormView(false);
				} else {
					$location.path(newURL);
					return;
				}
			}
		}, function() {
			// cancel selected, do not change view
			// reset prompt for changes for next time through
			c.data.promptChangesStarted = false;			
		});
	}
	$rootScope.$on("sp.form.ui_action.uiActionComplete", function (event, params) {
		c.data.submitting = false;
		// if this control is saving based on the modal prompt, reset form view
		if(c.data.promptChangesStarted){
			c.data.sys_id = params.rec_sys_id;
			_switchTaskFormView(false);
			c.data.promptChangesStarted=false;
		}
		// if in modal, the modal should close
		if(c.data.isModal){
			$scope.$parent.$parent.$dismiss();
		}

		// enable form
		// if not save as draft, update or cancel, then redirect to new page
		if(params.action){
			if(params.action.action_name != "save_as_draft" &&
				 params.action.action_name != "sysverb_update"){
				$scope.data.sys_id=params.rec_sys_id;
				$scope.data.getURL=true;
				// without this check there were a couple of unexpected errors in the browser
				if($scope.data.settings &&
					 $scope.data.settings.defaultTaskFormView){
					$scope.data.view=$scope.data.settings.defaultTaskFormView.sn_view;
				}
				spUtil.update($scope).then(function(data) {
					var redirectUrlNew = data.portal_url_ref + '?id=' +  data.pageId + '&sys_id=' + data.sys_id + '&table=' + data.pageTable + '&view=' + data.view;
					// prevent dirty message on new task saved
					c.data.redirectToNew = true;
					$location.url(redirectUrlNew);
				});			
			} else{
				c.data.sys_id = params.rec_sys_id;
				// set new object to current if not set
				if(!newObjSelected){
					newObjSelected = $scope.data.settings.defaultTaskFormView;
				}
				_switchTaskFormView(false);
			}
		}
	});

	$rootScope.$on("sp.form.ui_action.triggered", function (event, action) {
		c.data.submitting = true;
		// action triggered disable selector until finished	
	});

	function _switchTaskFormView(saveChanges){
		c.data.submitting = true;
		// change selected item in HTML before post back so selection is updated quickly
		c.data.selected_id = newObjSelected.sys_id;

		if(c.data.sys_id && c.data.sys_id != -1){
			var search = $location.search();
			search.sys_id = c.data.sys_id;
			search.view = newObjSelected.sn_view;
			search.spa = 1;
			$location.search(search).replace();
		}

		// if task exists, update the saved task to switch to a different view
		if(saveChanges && c.data.sys_id && c.data.sys_id != -1){
			c.data.new_task_widget_forms[0].widget.updateDraft(newObjSelected);	
		}
		if(c.data.view == newObjSelected.sn_view){
			$scope.data.skipReload = true;
		} else {
			$scope.data.skipReload = false;
		}


		$scope.data.defaultTaskFormViewUpdated = true;
		// newObjSelected is set in the selectType function
		$scope.data.settings.defaultTaskFormView = undefined; // clear previous object
		$scope.data.settings.defaultTaskFormView = newObjSelected;
		$scope.data.sys_id = c.data.sys_id;
		// DFCT0011069 - if no change to the view, then just update the fields, 
		//               don't post back to reload the form
		spUtil.update($scope).then(function(){
			c.data.submitting = false;
		});
		// DFCT0011069 - if form not reloaded, still update values
		if($scope.data.skipReload == true){
			_setFilterFields();	
		}
	}

	// when the form is loaded, this event will fire from sub form
	$rootScope.$on("spModel.gForm.rendered", function (event, params) {
		// DFCT0011069 - tasker type was not getting set when form changed, this should reset it any other fields in the fitler
		// wait for form to finish rendering
		_setFilterFields();
	});

	// DFCT0011069 - tasker type was not getting set when form changed, this should reset it any other fields in the fitler
	function _setFilterFields(){
		var fieldValues = [];
		var aFields = [];
		var fieldNameValue = [];
		aFields = newObjSelected.filter.split("^");
		aFields.forEach(function(fieldPair){
			if(fieldPair && fieldPair != ""){
				var fieldNameValuePair = {};
				fieldNameValue = fieldPair.split("=");
				fieldNameValuePair.field = fieldNameValue[0];
				fieldNameValuePair.value = fieldNameValue[1];
				fieldValues.push(fieldNameValuePair);				
			}
		});

		c.data.new_task_widget_forms[0].widget.setFieldValues(fieldValues);	
	}

	$scope.convertIsModalToString = function(){
		var result = String(c.data.isModal) || 'false';

		return result;
	}

};

sp_widget.css:
.dtech-new-task-container {
  display: flex;
  width:100%;
  height:100%
}

.flex-child {
  flex: 1;
  display:flex;
  flex-direction:column;
  /* position relative allowed flex to apply to the panel */
  position: relative;
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
}  

.flex-child:first-child {
  flex: .4;
} 

/* 2.8 | 2022-07-10 | mmcc | DFCT0011031 - Scrolling doesn't work on the "New" task form. "Advanced Task" fields don't display */
.detech-flex-shadow-25 {
  box-shadow: 0px 0px 30px 0px rgba(0, 0, 0, 0.25);
}  


/* NOTE: below here should be updated to use dtech naming convention
Once upddated to handle list selector with right side pointer, it should 
move into the service portal style sheets and imported
*/

.component-selector {
  /*background: linear-gradient(to right, #F5F7F9 0%, #F5F7F9 90%, #DDD 100%);*/
  background: #F5F7F9;
}

.component-selector-divider {
  width: 100%;
  height: 2px;
  background-color: rgba(221, 221, 221, 1);
}

.component-selector-header{
  color: rgba(117, 117, 117, 1); /*508 AA*/
  width: 100%;
  padding: 14px 20px 14px 20px;
  font-size: 14px;
  font-weight: 400;
  text-transform: uppercase;
}

.ul-selector {
  margin: 0px;
  padding: 0px;
  list-style-type: none;
  color:#757575;
}

.li-flex-row {
  display: flex;
  flex-grow:0;
  width:100%;
  flex-direction:row;
}

.flex-text {
  flex-grow:1;
}

.li-flex-row-child:first-child {
  flex-grow:1;
}

.li-flex-row-left-pointer {
  width: 0px;
  height: 0px;
  border-left: 10px solid transparent;
  border-right: 10px solid  white;
  border-top: 10px solid  transparent;
  border-bottom: 10px solid  transparent;
  margin: 0px auto;
  z-index: 1000;
}

.li-selector {
  padding: 14px 0px 14px 40px;
  width: 100%;
  color: rgba(0, 0, 0, 1);
  font-size: 14px;
  font-weight: 400;
  cursor:pointer;
}

.li-selector:hover{
  background-color: rgba(217, 237, 247, 1);
}

.li-selected{
  background-color: rgba(231, 244, 253, 1);
}

